-- Create dedicated user and database for n8n
CREATE USER :"N8N_DB_USER" WITH PASSWORD :'N8N_DB_PASS';
CREATE DATABASE :"N8N_DB_NAME" OWNER :"N8N_DB_USER";

\connect :"N8N_DB_NAME"

-- Create isolated schema for n8n and set search_path
CREATE SCHEMA IF NOT EXISTS :"N8N_DB_SCHEMA" AUTHORIZATION :"N8N_DB_USER";
GRANT USAGE ON SCHEMA :"N8N_DB_SCHEMA" TO :"N8N_DB_USER";
ALTER ROLE :"N8N_DB_USER" SET search_path TO :"N8N_DB_SCHEMA", public;

-- Create read-only user for MCP server
-- This script creates a user with read-only access to the N8N schema

-- Create the read-only role
CREATE ROLE mcp_readonly WITH
    LOGIN
    NOSUPERUSER
    NOCREATEDB
    NOCREATEROLE
    NOREPLICATION
    PASSWORD :'MCP_READONLY_DB_PASSWORD';

-- Grant connect permission to the database
GRANT CONNECT ON DATABASE n8n TO mcp_readonly;

-- Grant usage on the schema
GRANT USAGE ON SCHEMA n8n TO mcp_readonly;

-- Grant SELECT on all existing tables in the schema
GRANT SELECT ON ALL TABLES IN SCHEMA n8n TO mcp_readonly;

-- Grant SELECT on all future tables in the schema
ALTER DEFAULT PRIVILEGES IN SCHEMA n8n GRANT SELECT ON TABLES TO mcp_readonly;

-- Grant USAGE on all sequences (needed for reading serial columns)
GRANT USAGE ON ALL SEQUENCES IN SCHEMA n8n TO mcp_readonly;

-- Grant USAGE on future sequences
ALTER DEFAULT PRIVILEGES IN SCHEMA n8n GRANT USAGE ON SEQUENCES TO mcp_readonly;

-- Set search path for the user
ALTER ROLE mcp_readonly SET search_path TO n8n, public;

