-- Create email schema tables for Gmail data storage

-- Set schema context
SET search_path TO :"EMAIL_SCHEMA";

-- Gmail labels table
CREATE TABLE IF NOT EXISTS gmail_labels (
    label_id TEXT PRIMARY KEY,
    label_name TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);
COMMENT ON TABLE gmail_labels IS 'Gmail label definitions';
COMMENT ON COLUMN gmail_labels.label_id IS 'Gmail label identifier';
COMMENT ON COLUMN gmail_labels.label_name IS 'Human-readable label name';

-- Gmail messages table
CREATE TABLE IF NOT EXISTS gmail_message (
    gmail_id TEXT PRIMARY KEY,
    gmail_thread_id TEXT NOT NULL,
    size_estimate INTEGER,
    label_ids TEXT[],
    subject TEXT,
    sent_at TIMESTAMP WITH TIME ZONE,
    message_id_hdr TEXT UNIQUE,
    from_addrs JSONB,
    to_addrs JSONB,
    reply_to_addrs JSONB,
    headers JSONB,
    body_html TEXT,
    body_text TEXT,
    body_text_as_html TEXT,
    raw JSONB,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE gmail_message IS 'Gmail message data and metadata';
COMMENT ON COLUMN gmail_message.gmail_id IS 'Unique Gmail message ID';
COMMENT ON COLUMN gmail_message.gmail_thread_id IS 'Thread this message belongs to';
COMMENT ON COLUMN gmail_message.size_estimate IS 'Estimated message size in bytes';
COMMENT ON COLUMN gmail_message.label_ids IS 'Array of label IDs applied to message';
COMMENT ON COLUMN gmail_message.subject IS 'Email subject line';
COMMENT ON COLUMN gmail_message.sent_at IS 'When email was sent';
COMMENT ON COLUMN gmail_message.message_id_hdr IS 'Message-ID header value';
COMMENT ON COLUMN gmail_message.from_addrs IS 'Sender addresses structure';
COMMENT ON COLUMN gmail_message.to_addrs IS 'Recipient addresses structure';
COMMENT ON COLUMN gmail_message.reply_to_addrs IS 'Reply-to addresses';
COMMENT ON COLUMN gmail_message.headers IS 'Full email headers';
COMMENT ON COLUMN gmail_message.body_html IS 'HTML body content';
COMMENT ON COLUMN gmail_message.body_text IS 'Plain text body';
COMMENT ON COLUMN gmail_message.body_text_as_html IS 'Text body converted to HTML';
COMMENT ON COLUMN gmail_message.raw IS 'Complete raw message data';

-- Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_gmail_message_thread_id ON gmail_message(gmail_thread_id);
CREATE INDEX IF NOT EXISTS idx_gmail_message_sent_at ON gmail_message(sent_at DESC);
CREATE INDEX IF NOT EXISTS idx_gmail_message_label_ids ON gmail_message USING GIN(label_ids);
CREATE INDEX IF NOT EXISTS idx_gmail_message_from_addrs ON gmail_message USING GIN(from_addrs);
CREATE INDEX IF NOT EXISTS idx_gmail_message_to_addrs ON gmail_message USING GIN(to_addrs);
CREATE INDEX IF NOT EXISTS idx_gmail_message_headers ON gmail_message USING GIN(headers);

-- Email categorization tracking table
CREATE TABLE IF NOT EXISTS email_categorization (
    id SERIAL PRIMARY KEY,
    gmail_id TEXT NOT NULL REFERENCES gmail_message(gmail_id) ON DELETE CASCADE,
    category TEXT NOT NULL,
    confidence TEXT CHECK (confidence IN ('high', 'medium', 'low')),
    classification_method TEXT CHECK (classification_method IN ('rule', 'ai', 'manual')),
    ai_model TEXT,
    ai_prompt TEXT,
    ai_response JSONB,
    processed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(gmail_id, category)
);

COMMENT ON TABLE email_categorization IS 'Email categorization results and metadata';
COMMENT ON COLUMN email_categorization.gmail_id IS 'Reference to gmail_message';
COMMENT ON COLUMN email_categorization.category IS 'Assigned category';
COMMENT ON COLUMN email_categorization.confidence IS 'Classification confidence level';
COMMENT ON COLUMN email_categorization.classification_method IS 'How the classification was determined';
COMMENT ON COLUMN email_categorization.ai_model IS 'AI model used if applicable';
COMMENT ON COLUMN email_categorization.ai_response IS 'Full AI response for debugging';

-- Create index for categorization lookups
CREATE INDEX IF NOT EXISTS idx_email_categorization_gmail_id ON email_categorization(gmail_id);
CREATE INDEX IF NOT EXISTS idx_email_categorization_category ON email_categorization(category);
CREATE INDEX IF NOT EXISTS idx_email_categorization_processed_at ON email_categorization(processed_at DESC);

-- Digest generation tracking
CREATE TABLE IF NOT EXISTS digest_generation (
    id SERIAL PRIMARY KEY,
    digest_type TEXT NOT NULL,
    generated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    email_count INTEGER DEFAULT 0,
    digest_content TEXT,
    sent_to TEXT[],
    status TEXT DEFAULT 'pending',
    error_message TEXT
);

COMMENT ON TABLE digest_generation IS 'Track digest email generation';
CREATE INDEX IF NOT EXISTS idx_digest_generation_type ON digest_generation(digest_type);
CREATE INDEX IF NOT EXISTS idx_digest_generation_generated_at ON digest_generation(generated_at DESC);

-- =====================================
-- Email Classification Schema (from migration)
-- =====================================

-- Reference: Categories (Hierarchical)
CREATE TABLE IF NOT EXISTS category (
  category_id        SERIAL PRIMARY KEY,
  code               TEXT NOT NULL UNIQUE,              -- e.g. 'financial', 'financial.receipt', 'financial.statement'
  display_name       TEXT NOT NULL,
  description        TEXT,
  category_level     TEXT NOT NULL CHECK (category_level IN ('top_level','subtype')),
  parent_category_id INT REFERENCES category(category_id),  -- NULL for top-level
  category_type      TEXT NOT NULL CHECK (category_type IN ('rule_based','ai_assisted','meta')),
  gmail_label        TEXT,                              -- mapped Gmail label (e.g. receipts)
  active             BOOLEAN NOT NULL DEFAULT TRUE,
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CONSTRAINT chk_parent_level CHECK (
    (category_level = 'top_level' AND parent_category_id IS NULL) OR
    (category_level = 'subtype' AND parent_category_id IS NOT NULL)
  )
);

COMMENT ON TABLE category IS 'Hierarchical classification categories with top-level and subtype support.';
CREATE INDEX IF NOT EXISTS idx_category_parent ON category(parent_category_id) WHERE parent_category_id IS NOT NULL;

-- Classification Session (One session per end-to-end pipeline attempt for a message)
CREATE TABLE IF NOT EXISTS classification_session (
  session_id         BIGSERIAL PRIMARY KEY,
  gmail_id           TEXT NOT NULL REFERENCES gmail_message(gmail_id) ON DELETE CASCADE,
  pipeline_version   TEXT NOT NULL,                     -- semantic or git hash
  started_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  completed_at       TIMESTAMPTZ,
  final_category_id  INT REFERENCES category(category_id),
  final_confidence   NUMERIC(5,2),
  final_rationale    TEXT,
  final_keywords     TEXT[],                            -- aggregated salient terms
  final_features     JSONB,                             -- consolidated feature map
  ai_routing_used    BOOLEAN DEFAULT FALSE,             -- Whether AI classification was invoked
  status             TEXT NOT NULL DEFAULT 'in_progress' CHECK (status IN ('in_progress','completed','aborted')),
  triggered_by       TEXT NOT NULL DEFAULT 'system',    -- system|human|reprocess
  UNIQUE (gmail_id, pipeline_version, started_at)
);

COMMENT ON TABLE classification_session IS 'Top-level run context for staged classification of a message.';

-- Classification Stage (Each discrete step in classification pipeline)
CREATE TABLE IF NOT EXISTS classification_stage (
  stage_id           BIGSERIAL PRIMARY KEY,
  session_id         BIGINT NOT NULL REFERENCES classification_session(session_id) ON DELETE CASCADE,
  stage_order        SMALLINT NOT NULL,                 -- sequence within session
  stage_type         TEXT NOT NULL,                     -- e.g. 'rule_match','feature_extraction','ai_classification','human_review'
  started_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  ended_at           TIMESTAMPTZ,
  decision_category_id INT REFERENCES category(category_id), -- if stage concluded with a primary category decision
  decision_polarity  TEXT CHECK (decision_polarity IN ('positive','negative','none')),
  decision_confidence NUMERIC(5,2),
  weight_score       JSONB,                             -- weight score object: {total_weight, stage_type, categories_processed}
  rationale          TEXT,                              -- summary rationale for primary decision
  keywords           TEXT[],                            -- salient terms for this stage
  features           JSONB,                             -- raw feature extraction output (for feature_extraction stage)
  passed_to_next     BOOLEAN,                           -- true if pipeline continued
  CONSTRAINT uq_stage_order UNIQUE (session_id, stage_order)
);

COMMENT ON TABLE classification_stage IS 'Discrete step in the classification pipeline.';

-- Stage Category Evaluation (One row per (stage, category) considered)
CREATE TABLE IF NOT EXISTS stage_category_eval (
  eval_id            BIGSERIAL PRIMARY KEY,
  stage_id           BIGINT NOT NULL REFERENCES classification_stage(stage_id) ON DELETE CASCADE,
  category_id        INT NOT NULL REFERENCES category(category_id),
  decision           TEXT NOT NULL CHECK (decision IN ('positive','negative','candidate','rejected')),
  score              JSONB NOT NULL,                    -- score object: {score, confidence, scoring_components, rationale, selected_subtype_id, decision}
  confidence         NUMERIC(5,2),                      -- probability or normalized
  weight_components  JSONB,                             -- breakdown of rule contributions
  scoring_components JSONB,                             -- Detailed scoring breakdown
  selected_subtype_id INT REFERENCES category(category_id),  -- Selected subtype if category chosen
  rationale          TEXT,                              -- per-category reasoning
  keywords           TEXT[],                            -- per-category salient terms
  feature_vector     JSONB,                             -- subset features relevant
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (stage_id, category_id)
);

COMMENT ON TABLE stage_category_eval IS 'Per-category evaluation details with comprehensive scoring breakdown.';

-- Extracted Features (optional granular list)
CREATE TABLE IF NOT EXISTS extracted_feature (
  feature_id         BIGSERIAL PRIMARY KEY,
  stage_id           BIGINT NOT NULL REFERENCES classification_stage(stage_id) ON DELETE CASCADE,
  name               TEXT NOT NULL,                     -- e.g. 'has_tracking_number'
  value              TEXT,                              -- normalized string form
  importance         NUMERIC(5,2),                      -- relative weight/impact
  evidence_snippet   TEXT,                              -- text snippet supporting feature
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE extracted_feature IS 'Atomic features derived at feature extraction stages.';

-- Session Categories (Multi-Label Support)
CREATE TABLE IF NOT EXISTS session_categories (
  session_id         BIGINT NOT NULL REFERENCES classification_session(session_id) ON DELETE CASCADE,
  category_id        INT NOT NULL REFERENCES category(category_id),
  subtype_id         INT REFERENCES category(category_id),  -- Selected subtype within category
  is_primary         BOOLEAN DEFAULT FALSE,
  confidence         NUMERIC(5,2) NOT NULL,
  category_score     NUMERIC(6,2),                      -- Raw category score from scoring engine
  hard_assertion     BOOLEAN DEFAULT FALSE,             -- Was hard assertion triggered
  ai_classified      BOOLEAN DEFAULT FALSE,             -- Was this from AI classification
  scoring_trace      JSONB,                             -- Complete scoring trace for this category
  label_order        SMALLINT,                          -- 1 for primary, 2 for secondary, etc.
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (session_id, category_id)
);

COMMENT ON TABLE session_categories IS 'Multi-label classification results per session with scoring details.';
CREATE INDEX IF NOT EXISTS idx_session_categories_primary ON session_categories(session_id) WHERE is_primary = TRUE;

-- Detected Attributes
CREATE TABLE IF NOT EXISTS detected_attributes (
  attribute_id       BIGSERIAL PRIMARY KEY,
  session_id         BIGINT NOT NULL REFERENCES classification_session(session_id) ON DELETE CASCADE,
  stage_id           BIGINT REFERENCES classification_stage(stage_id),
  attribute_name     TEXT NOT NULL,                     -- e.g. 'self_sent', 'from_financial_institution'
  attribute_value    TEXT,                              -- Value if not boolean
  detection_method   TEXT,                              -- 'regex', 'domain_lookup', 'derived', etc.
  detection_evidence TEXT,                              -- What triggered detection
  influence_role     TEXT CHECK (influence_role IN ('CORE','PRIMARY_BOOST','SECONDARY_BOOST',
                                                    'DISAMBIGUATOR','FILTER','STRUCTURAL',
                                                    'DERIVED_LINK','NEUTRAL')),
  categories_influenced TEXT[],                         -- Which categories this attribute affected
  total_bonus_applied NUMERIC(4,2),                     -- Sum of all bonuses from this attribute
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (session_id, attribute_name)
);

COMMENT ON TABLE detected_attributes IS 'Attributes detected during classification and their scoring influence.';
CREATE INDEX IF NOT EXISTS idx_detected_attributes_session ON detected_attributes(session_id);
CREATE INDEX IF NOT EXISTS idx_detected_attributes_name ON detected_attributes(attribute_name);

-- Domain Signal Resolutions
CREATE TABLE IF NOT EXISTS domain_signal_resolutions (
  resolution_id      BIGSERIAL PRIMARY KEY,
  session_id         BIGINT NOT NULL REFERENCES classification_session(session_id) ON DELETE CASCADE,
  domain             TEXT NOT NULL,
  signal_type        TEXT NOT NULL CHECK (signal_type IN ('hard_assertion','strong_indicator','weak_signal')),
  matched_category_id INT REFERENCES category(category_id),
  confidence_level   TEXT,                              -- 'high', 'medium', 'low'
  domain_type        TEXT,                              -- 'financial', 'newsletter', 'logistics', etc.
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE domain_signal_resolutions IS 'Domain-based signals resolved during classification.';
CREATE INDEX IF NOT EXISTS idx_domain_signals_session ON domain_signal_resolutions(session_id);

-- Human Overrides / Corrections
CREATE TABLE IF NOT EXISTS human_override (
  override_id        BIGSERIAL PRIMARY KEY,
  session_id         BIGINT NOT NULL REFERENCES classification_session(session_id) ON DELETE CASCADE,
  previous_category_ids INT[],                          -- Previous category IDs (multi-label)
  new_category_ids   INT[],                             -- New category IDs (multi-label)
  previous_category_id INT REFERENCES category(category_id),  -- Deprecated, use arrays
  new_category_id    INT REFERENCES category(category_id),     -- Deprecated, use arrays
  reason             TEXT,
  user_id            TEXT,                              -- operator identifier
  created_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE human_override IS 'Manual corrections to classification decisions supporting multi-label.';

-- Additional indexes for classification tables
CREATE INDEX IF NOT EXISTS idx_class_session_message ON classification_session(gmail_id, started_at DESC);
CREATE INDEX IF NOT EXISTS idx_stage_session_order ON classification_stage(session_id, stage_order);
CREATE INDEX IF NOT EXISTS idx_stage_decision_positive ON classification_stage(decision_category_id) WHERE decision_polarity = 'positive';
CREATE INDEX IF NOT EXISTS idx_eval_category ON stage_category_eval(category_id);
CREATE INDEX IF NOT EXISTS idx_eval_positive_negative ON stage_category_eval(category_id, decision) WHERE decision IN ('positive','negative');
CREATE INDEX IF NOT EXISTS idx_feature_name ON extracted_feature(name);

-- Views for classification data
CREATE OR REPLACE VIEW v_latest_decision AS
SELECT DISTINCT ON (m.gmail_id)
  m.gmail_id,
  cs.session_id,
  cs.final_category_id,
  c.code AS final_category_code,
  cs.final_confidence,
  cs.final_rationale,
  cs.ai_routing_used,
  cs.completed_at
FROM gmail_message m
JOIN classification_session cs ON cs.gmail_id = m.gmail_id AND cs.status = 'completed'
LEFT JOIN category c ON c.category_id = cs.final_category_id
ORDER BY m.gmail_id, cs.completed_at DESC;

COMMENT ON VIEW v_latest_decision IS 'Latest classification session per Gmail message (use v_latest_decision_labels for multi-label).';

CREATE OR REPLACE VIEW v_latest_decision_labels AS
SELECT
  m.gmail_id,
  cs.session_id,
  cs.completed_at,
  cs.ai_routing_used,
  array_agg(
    json_build_object(
      'category_code', cat.code,
      'category_name', cat.display_name,
      'subtype_code', sub.code,
      'subtype_name', sub.display_name,
      'confidence', sc.confidence,
      'score', sc.category_score,
      'is_primary', sc.is_primary,
      'hard_assertion', sc.hard_assertion,
      'ai_classified', sc.ai_classified,
      'label_order', sc.label_order
    ) ORDER BY sc.label_order, sc.confidence DESC
  ) AS labels
FROM gmail_message m
JOIN classification_session cs ON cs.gmail_id = m.gmail_id AND cs.status = 'completed'
JOIN session_categories sc ON sc.session_id = cs.session_id
JOIN category cat ON cat.category_id = sc.category_id
LEFT JOIN category sub ON sub.category_id = sc.subtype_id
WHERE cs.completed_at = (
  SELECT MAX(completed_at)
  FROM classification_session
  WHERE gmail_id = m.gmail_id AND status = 'completed'
)
GROUP BY m.gmail_id, cs.session_id, cs.completed_at, cs.ai_routing_used;

COMMENT ON VIEW v_latest_decision_labels IS 'Latest multi-label classification results with full details.';

CREATE OR REPLACE VIEW v_category_hierarchy AS
SELECT
  parent.category_id AS top_level_id,
  parent.code AS top_level_code,
  parent.display_name AS top_level_name,
  child.category_id AS subtype_id,
  child.code AS subtype_code,
  child.display_name AS subtype_name,
  child.gmail_label
FROM category parent
LEFT JOIN category child ON child.parent_category_id = parent.category_id
WHERE parent.category_level = 'top_level'
ORDER BY parent.code, child.code;

COMMENT ON VIEW v_category_hierarchy IS 'Hierarchical view of categories and their subtypes.';

