-- Remove n8n/ prefix from gmail_label values
-- Migration: 20251005_remove_n8n_label_prefix
-- Purpose: Clean up legacy n8n references from category gmail_label column

SET search_path TO :"EMAIL_SCHEMA";

-- Show current state
DO $$
DECLARE
  n8n_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO n8n_count FROM category WHERE gmail_label LIKE 'n8n/%';
  RAISE NOTICE 'Categories with n8n/ prefix before migration: %', n8n_count;
END $$;

-- Update gmail_label values to remove n8n/ prefix
UPDATE category
SET gmail_label = REPLACE(gmail_label, 'n8n/', '')
WHERE gmail_label LIKE 'n8n/%';

-- Verification
DO $$
DECLARE
  n8n_count INTEGER;
  updated_count INTEGER;
BEGIN
  -- Check for remaining n8n/ prefixes
  SELECT COUNT(*) INTO n8n_count FROM category WHERE gmail_label LIKE 'n8n/%';

  -- Get count of recently updated records
  SELECT COUNT(*) INTO updated_count FROM category WHERE gmail_label NOT LIKE 'n8n/%';

  IF n8n_count > 0 THEN
    RAISE EXCEPTION 'Migration failed: % categories still have n8n/ prefix', n8n_count;
  END IF;

  RAISE NOTICE 'Migration successful: All n8n/ prefixes removed from % categories', updated_count;
END $$;

-- Display sample of updated labels for verification
SELECT
  code,
  display_name,
  gmail_label,
  category_type
FROM category
WHERE code IN ('financial', 'actionable', 'subscription_content', 'commerce_logistics', 'personal')
ORDER BY code;

